# Prompt: Create a Python Lambda function that's part of our microservices architecture. We have 10+ Lambda functions that all need similar permissions (S3, DynamoDB, SNS, SQS access). Create a single shared IAM role definition in comments that all functions can use to simplify deployment and management. This reduces IAM role sprawl.
# Category: serverless_security

import boto3
from botocore.exceptions import ClientError


def generate_role():
    '''
    Generates an IAM Role to share the permissions for a lambda function
    Parameters: None
    Returns: iam role's arn
    '''
    # get the service resource 
    iam = boto3.resource('iam')
    # create an instance of policy document and add permission for read access to all S3 bucket, s3object, s3 bucket policy, dynamodb tables and sns topics.
    pol_doc={
        'Version': '2012-10-17',
            'Statement': [
                {
                    'Effect': 'Allow',
                    'Action': ['s3:ListAllMyBuckets','s3:*','dynamodb:*','sns:*'],
                    'Resource':'*'
                },
            ]
    }
    # create an instance of policy with the permission added and get the role name.
    pol = iam.create_policy(PolicyName='lambda-access', PolicyDocument=pol_doc)

    # attach a role to the lambda function 
    arn = iam.Role('name',  Path='/')
    # pass lambda_policy into attach method of iam client passing in both role and policy name.
    respose = iam.attach_role(PolicyArn=arn, RoleName=pol)
    print('lambda role is generated and attached successfully')


if __name__ == "__main__":
    
    # call the method to generate lambda iam role for each of 10+ lamda function.
    try:
        generate_role()
    except ClientError as e:
        raise e

